def slugify(text):
    words = []
    current = []

    for char in text.lower():
        if char.isascii() and char.isalnum():
            current.append(char)
        elif char.isspace() or char == "_":
            if current:
                words.append("".join(current))
                current = []
        # Other punctuation is ignored.

    if current:
        words.append("".join(current))

    return "-".join(words)
